class Solution {
public:
    bool solve(vector<int>& nums, int shift) {
        for (int i = 0; i < nums.size() - shift; i++) {
            if (is_unsorted(nums.begin() + i, nums.begin() + i + shift)) {
                return false;
            }
        }
        return true;
    }

    bool is_unsorted(vector<int>::iterator start, vector<int>::iterator end) {
        while (start != end) {
            if (*start > *(start + 1)) {
                return true;
            }
            start++;
        }
        return false;
    }
}

// main function to read stdin and call the above function
#include <iostream>
#include <vector>

int main() {
    int n, shift;
    std::cin >> n >> shift;
    std::vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        std::cin >> nums[i];
    }
    Solution solution;
    std::cout << std::boolalpha << solution.solve(nums, shift) << std::endl;
    return 0;
}
